// PDF Generator using jsPDF and jsPDF-AutoTable for E-Jurnal

// Helper to fetch external image and convert to Base64 to avoid jsPDF CORS issues
async function fetchImageAsBase64(url) {
    try {
        const proxies = [
            url, // Try direct first
            `https://corsproxy.io/?${encodeURIComponent(url)}`,
            `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`
        ];
        
        for (const p of proxies) {
            try {
                const response = await fetch(p);
                if (response.ok) {
                    const blob = await response.blob();
                    return await new Promise((resolve, reject) => {
                        const reader = new FileReader();
                        reader.onloadend = () => resolve(reader.result);
                        reader.onerror = reject;
                        reader.readAsDataURL(blob);
                    });
                }
            } catch(e) {}
        }
        return null;
    } catch (e) {
        console.warn('Failed to fetch image:', e);
        return null;
    }
}

const formatShortDate = (dateStr) => {
    if (!dateStr) return '';
    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return dateStr;
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun', 'Jul', 'Agt', 'Sep', 'Okt', 'Nov', 'Des'];
    const day = d.getDate().toString().padStart(2, '0');
    return `${day} ${months[d.getMonth()]} ${d.getFullYear()}`;
};

const applyRoundedCornersToImage = (base64Str, cornerRadius = 30) => {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
            const canvas = document.createElement('canvas');
            canvas.width = img.width;
            canvas.height = img.height;
            const ctx = canvas.getContext('2d');
            
            ctx.beginPath();
            ctx.moveTo(cornerRadius, 0);
            ctx.lineTo(img.width - cornerRadius, 0);
            ctx.quadraticCurveTo(img.width, 0, img.width, cornerRadius);
            ctx.lineTo(img.width, img.height - cornerRadius);
            ctx.quadraticCurveTo(img.width, img.height, img.width - cornerRadius, img.height);
            ctx.lineTo(cornerRadius, img.height);
            ctx.quadraticCurveTo(0, img.height, 0, img.height - cornerRadius);
            ctx.lineTo(0, cornerRadius);
            ctx.quadraticCurveTo(0, 0, cornerRadius, 0);
            ctx.closePath();
            
            ctx.clip();
            ctx.drawImage(img, 0, 0);
            resolve(canvas.toDataURL('image/png'));
        };
        img.onerror = reject;
        img.src = base64Str;
    });
};

async function generateJurnalPDF(data, teacherName, dokData = []) {
    if (!window.jspdf) {
        throw new Error('jsPDF library not loaded');
    }
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF('l', 'mm', 'a4'); // Landscape A4

    // Calculate Academic Year automatically
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth(); // 0 = Jan, 11 = Dec
    const academicYear = currentMonth >= 6 ? `${currentYear}/${currentYear + 1}` : `${currentYear - 1}/${currentYear}`;

    // Helper to find signature data from DOK sheet
    const getDokData = (keyword) => {
        const found = dokData.find(d => {
            const kat = String(d.KATEGORI || d.Kategori || d.kategori || '').toUpperCase();
            return kat.includes(keyword.toUpperCase());
        });
        return found || { Nama: '.......................', NIP: '-' };
    };

    const kepsek = getDokData('KEPALA SEKOLAH');
    const wakakur = getDokData('WAKIL KEPALA SEKOLAH') || getDokData('KURIKULUM');

    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 10;

    // Header
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('REKAP DATA JURNAL MENGAJAR GURU', pageWidth / 2, margin + 8, { align: 'center' });

    doc.setFontSize(11);
    doc.setFont('helvetica', 'normal');
    doc.text(`TAHUN PELAJARAN ${academicYear}`, pageWidth / 2, margin + 14, { align: 'center' });

    // Teacher info & Date
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Guru: ${teacherName}`, margin, margin + 25);

    const currentDate = now.toLocaleDateString('id-ID', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
    });
    // Tanggal Cetak on the right side
    doc.text(`Tanggal Cetak: ${currentDate}`, pageWidth - margin, margin + 25, { align: 'right' });

    // Embed logo
    try {
        const base64data = 'data:image/png;base64,' + '';
        doc.addImage(base64data, 'PNG', margin, margin, 20, 20);
    } catch (e) {
        console.warn('Failed to load logo for PDF', e);
    }

    // Helper to safely get value from object keys
    const getVal = (obj, keys) => {
        for (let k of keys) if (obj[k] !== undefined && obj[k] !== null) return obj[k];
        return '';
    };

    // Helper to count students from string or number
    const getCount = (val) => {
        if (val === undefined || val === null || val === '') return 0;
        if (typeof val === 'number') return val;
        return String(val).split(',').filter(x => x.trim()).length;
    };

    // Prepare table data
    const tableData = data.map((row, index) => {
        const total = Number(getVal(row, ['JUMLAH_SISWA', 'TOTAL_SISWA', 'Total_Siswa', 'jumlah']) || 0);
        const alphaList = getVal(row, ['SISWA_ALPHA', 'ALPHA', 'Alpha', 'alpha']) || '';
        const izinList = getVal(row, ['SISWA_IZIN', 'IZIN', 'Izin', 'izin']) || '';
        const sakitList = getVal(row, ['SISWA_SAKIT', 'SAKIT', 'Sakit', 'sakit']) || '';
        const alphaCnt = getCount(alphaList);
        const izinCnt = getCount(izinList);
        const sakitCnt = getCount(sakitList);
        const hadirCnt = total - (alphaCnt + izinCnt + sakitCnt);
        return [
            index + 1,
            getVal(row, ['TANGGAL', 'Tanggal', 'tanggal']),
            getVal(row, ['HARI', 'Hari', 'hari']),
            getVal(row, ['JAM_KE', 'Jam_Ke', 'jam']),
            getVal(row, ['KELAS', 'Kelas', 'kelas']),
            getVal(row, ['RUANG', 'Ruang', 'ruang']),
            total,
            getVal(row, ['MAPEL', 'MATA_PELAJARAN', 'Mapel', 'mapel']), // corrected key order with MAPEL
            getVal(row, ['MATERI_PEMBELAJARAN', 'MATERI', 'Materi', 'materi']),
            hadirCnt,
            alphaList || '-',
            izinList || '-',
            sakitList || '-',
            getCount(getVal(row, ['JUMLAH_SISWA_TIDAK_HADIR', 'TIDAK_HADIR', 'Tidak_Hadir', 'tidakhadir'])) || (alphaCnt + izinCnt + sakitCnt)
        ];
    });

    const headers = ['No', 'Tanggal', 'Hari', 'Jam', 'Kelas', 'Rng', 'Jml', 'Mapel', 'Materi', 'H', 'A', 'I', 'S', 'TH'];

    // Generate table with adjusted column widths and alignment
    doc.autoTable({
        head: [headers],
        body: tableData,
        startY: margin + 30,
        margin: { left: margin, right: margin },
        styles: {
            fontSize: 7,
            cellPadding: 1.5,
            overflow: 'linebreak',
            halign: 'center',
            valign: 'middle',
            lineWidth: 0.1,
            lineColor: [200, 200, 200]
        },
        headStyles: {
            fillColor: [79, 70, 229], // Primary color
            textColor: [255, 255, 255],
            fontStyle: 'bold',
            halign: 'center',
            lineWidth: 0.1
        },
        columnStyles: {
            0: { cellWidth: 8 },   // No
            1: { cellWidth: 18 },  // Tanggal
            2: { cellWidth: 15 },  // Hari
            3: { cellWidth: 12 },  // Jam
            4: { cellWidth: 17 },  // Kelas (added 5mm)
            5: { cellWidth: 12 },  // Ruang
            6: { cellWidth: 10 },  // Jml
            7: { cellWidth: 35, halign: 'left' }, // Mapel
            8: { cellWidth: 40, halign: 'left' }, // Materi
            9: { cellWidth: 12, halign: 'center' }, // H (hadir count, centered)
            10: { cellWidth: 30, halign: 'left' }, // A (alpha names)
            11: { cellWidth: 30, halign: 'left' }, // I (izin names)
            12: { cellWidth: 30, halign: 'left' }, // S (sakit names)
            13: { cellWidth: 10, halign: 'center' } // TH
        },
        alternateRowStyles: {
            fillColor: [248, 250, 252]
        },
        didDrawPage: function (data) {
            const currentPage = doc.internal.getCurrentPageInfo().pageNumber;
            doc.setFontSize(8);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(100, 100, 100);

            // Footer text
            doc.text('Data diambil dari aplikasi E-Jurnal V 4.0.0 copyright 2026', margin, pageHeight - 8);

            // Page number
            doc.text(`${currentPage}`, pageWidth - margin - 5, pageHeight - 8, { align: 'right' });

            // Reset text color
            doc.setTextColor(0, 0, 0);
        }
    });

    const finalY = doc.lastAutoTable.finalY;
    let signatureY = finalY + 10;

    // Check if there's enough space for signatures (approx 45mm needed)
    if (signatureY + 45 > pageHeight - margin) {
        doc.addPage();
        signatureY = margin + 10;
    }

    // Summary text
    const totalRecords = data.length;
    const mapelColIndex = 7; // Mapel is index 7 in the mapped array
    const mapels = data.map(r => getVal(r, ['MAPEL', 'MATA_PELAJARAN', 'Mapel', 'mapel']));
    const uniqueSubjects = [...new Set(mapels)].filter(s => s).join(', ');

    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.text(`Total Pertemuan: ${totalRecords} | Mata Pelajaran: ${uniqueSubjects || '-'}`, margin, signatureY);

    signatureY += 12;

    // Signatures setup (Horizontal layout: Left = Kepsek, Center = Wakakur, Right = Guru)
    const signatureWidth = 70;
    const signatureHeight = 20;

    // Distribute evenly
    const sig1X = margin;
    const sig2X = (pageWidth / 2) - (signatureWidth / 2);
    const sig3X = pageWidth - margin - signatureWidth;

    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');

    // 1. Kepala Sekolah (Kiri)
    // Updated signature text
    doc.text('Mengetahui,', sig1X + signatureWidth / 2, signatureY, { align: 'center' });
    doc.text('Kepala SMK Negeri 1 Bumijawa', sig1X + signatureWidth / 2, signatureY + 4, { align: 'center' });



    doc.setFont('helvetica', 'bold');
    doc.text(kepsek.NAMA || kepsek.Nama || '.......................', sig1X + signatureWidth / 2, signatureY + signatureHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${kepsek.NIP || '-'}`, sig1X + signatureWidth / 2, signatureY + signatureHeight + 8, { align: 'center' });

    // 2. Wakil Kepala Sekolah (Tengah)
    doc.text('Wakil Kepala Sekolah', sig2X + signatureWidth / 2, signatureY, { align: 'center' });
    doc.text('Bidang Kurikulum', sig2X + signatureWidth / 2, signatureY + 4, { align: 'center' });

    doc.setFont('helvetica', 'bold');
    doc.text(wakakur.NAMA || wakakur.Nama || '.......................', sig2X + signatureWidth / 2, signatureY + signatureHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${wakakur.NIP || '-'}`, sig2X + signatureWidth / 2, signatureY + signatureHeight + 8, { align: 'center' });

    // 3. Guru Mata Pelajaran (Kanan)
    // Try to get NIP from localStorage userData
    const savedUser = JSON.parse(localStorage.getItem('userData') || '{}');
    const guruNip = savedUser.NIP || '-';

    // doc.text('Bumijawa, ' + currentDate, sig3X + signatureWidth / 2, signatureY, { align: 'center' });
    doc.text('Bumijawa, ' + currentDate, sig3X + signatureWidth / 2, signatureY, { align: 'center' });
    doc.text('Guru Mata Pelajaran', sig3X + signatureWidth / 2, signatureY + 4, { align: 'center' });

    doc.setFont('helvetica', 'bold');
    doc.text(teacherName, sig3X + signatureWidth / 2, signatureY + signatureHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${guruNip}`, sig3X + signatureWidth / 2, signatureY + signatureHeight + 8, { align: 'center' });

    // === LAMPIRAN DOKUMENTASI ===
    const docsWithImages = data.filter(r => r.DOKUMENTASI || r.FILE_ID_DRIVE || r.FILE_ID);
    
    if (docsWithImages.length > 0) {
        doc.addPage();
        let currentY = margin;
        
        // Header Lampiran
        doc.setFontSize(14);
        doc.setFont('helvetica', 'bold');
        doc.text('LAMPIRAN DOKUMENTASI JURNAL MENGAJAR', pageWidth / 2, currentY + 8, { align: 'center' });
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        doc.text(`Guru: ${teacherName}`, pageWidth / 2, currentY + 14, { align: 'center' });
        
        const startYOffset = currentY + 25;
        let imagesOnPage = 0;
        
        // Grid configuration (4 columns x 3 rows)
        const cols = 4;
        const rows = 3;
        const maxPerPage = cols * rows;
        
        const cellWidth = 65;
        const cellHeight = 55;
        const gapX = 4;
        const gapY = 4;
        
        // Calculate starting X to center the entire grid
        const gridTotalWidth = (cols * cellWidth) + ((cols - 1) * gapX);
        const startXOffset = margin + (pageWidth - 2 * margin - gridTotalWidth) / 2;
        
        for (let i = 0; i < docsWithImages.length; i++) {
            const row = docsWithImages[i];
            const tglRaw = getVal(row, ['TANGGAL', 'Tanggal', 'tanggal']);
            const tgl = formatShortDate(tglRaw);
            const kls = getVal(row, ['KELAS', 'Kelas', 'kelas']);
            const mpl = getVal(row, ['MAPEL', 'MATA_PELAJARAN', 'Mapel', 'mapel']);
            const mtr = getVal(row, ['MATERI_PEMBELAJARAN', 'MATERI', 'Materi', 'materi']);
            
            // New fields
            const rng = getVal(row, ['RUANG', 'Ruang', 'ruang']) || '-';
            const total = Number(getVal(row, ['JUMLAH_SISWA', 'TOTAL_SISWA', 'Total_Siswa', 'jumlah']) || 0);
            const alphaCnt = getCount(getVal(row, ['SISWA_ALPHA', 'ALPHA', 'Alpha', 'alpha']));
            const izinCnt = getCount(getVal(row, ['SISWA_IZIN', 'IZIN', 'Izin', 'izin']));
            const sakitCnt = getCount(getVal(row, ['SISWA_SAKIT', 'SAKIT', 'Sakit', 'sakit']));
            const hdr = total - (alphaCnt + izinCnt + sakitCnt);
            
            let displayUrl = row.DOKUMENTASI || '';
            if (displayUrl && !displayUrl.startsWith('data:image')) {
                const rawIdDrive = row.FILE_ID_DRIVE || row.FILE_ID || '';
                let fileId = (rawIdDrive && rawIdDrive !== "NOT FOUND" && !rawIdDrive.includes('LOCAL_CACHE')) ? rawIdDrive.trim() : '';
                if (!fileId) {
                    const idMatch = displayUrl.match(/[-\w]{25,}/);
                    if (idMatch) fileId = idMatch[0];
                }
                if (fileId) displayUrl = `https://lh3.googleusercontent.com/d/${fileId}=w400`; // Use smaller thumbnail for grid
            }
            
            let base64Img = null;
            if (displayUrl.startsWith('data:image')) {
                base64Img = displayUrl;
            } else if (displayUrl) {
                base64Img = await fetchImageAsBase64(displayUrl);
            }
            
            if (base64Img) {
                // Apply rounded corners to image
                base64Img = await applyRoundedCornersToImage(base64Img, 40);
                
                // Check if we need a new page
                if (imagesOnPage >= maxPerPage) {
                    doc.addPage();
                    doc.setFontSize(14);
                    doc.setFont('helvetica', 'bold');
                    doc.text('LAMPIRAN DOKUMENTASI JURNAL MENGAJAR (Lanjutan)', pageWidth / 2, margin + 8, { align: 'center' });
                    imagesOnPage = 0;
                }
                
                // Calculate grid position
                const colIndex = imagesOnPage % cols;
                const rowIndex = Math.floor(imagesOnPage / cols);
                
                const xPos = startXOffset + colIndex * (cellWidth + gapX);
                const yPos = startYOffset + rowIndex * (cellHeight + gapY);
                
                // Draw Border with rounded corners
                doc.setDrawColor(200, 200, 200);
                doc.setLineWidth(0.2);
                doc.roundedRect(xPos, yPos, cellWidth, cellHeight, 2, 2, 'S');
                
                // Draw Text neatly aligned in two columns for first 4 items
                const col1X = xPos + 2;
                const col2X = xPos + 32;
                
                doc.setFontSize(6.5);
                doc.setFont('helvetica', 'bold');
                doc.text(`Tgl : ${tgl}`, col1X, yPos + 4);
                doc.text(`Kls : ${kls}`, col2X, yPos + 4);
                
                doc.setFont('helvetica', 'normal');
                doc.text(`Rng : ${rng}`, col1X, yPos + 7);
                doc.text(`Hadir : ${hdr}`, col2X, yPos + 7);
                
                const maxMapelLen = 45;
                const mplText = mpl.length > maxMapelLen ? mpl.substring(0, maxMapelLen) + '...' : mpl;
                doc.text(`Mapel : ${mplText}`, col1X, yPos + 10);
                
                // Truncate materi
                const maxMateriLen = 45;
                const mtrText = mtr.length > maxMateriLen ? mtr.substring(0, maxMateriLen) + '...' : mtr;
                doc.text(`Materi : ${mtrText}`, col1X, yPos + 13);
                
                // Draw Image (Centered horizontally inside cell)
                const imgWidth = cellWidth - 4;
                const imgHeight = cellHeight - 17; 
                const imgX = xPos + 2;
                
                try {
                    doc.addImage(base64Img, imgX, yPos + 15, imgWidth, imgHeight);
                } catch(e) {
                    console.warn('Failed to add documentation image to PDF', e);
                }
                
                imagesOnPage++;
            }
        }
    }
    let dataBulan = 'SEMUA';
    if (data && data.length > 0) {
        const firstTgl = data[0].TANGGAL || data[0].Tanggal || data[0].tanggal;
        if (firstTgl) {
            const d = new Date(firstTgl);
            if (!isNaN(d.getTime())) {
                const months = ['JANUARI', 'FEBRUARI', 'MARET', 'APRIL', 'MEI', 'JUNI', 'JULI', 'AGUSTUS', 'SEPTEMBER', 'OKTOBER', 'NOVEMBER', 'DESEMBER'];
                dataBulan = months[d.getMonth()];
            }
        }
    }

    const nipFile = guruNip !== '-' ? guruNip : 'NONIP';
    const nameFile = teacherName.replace(/\s+/g, '').toUpperCase();
    const filename = `REKAPJURNAL_${dataBulan}_${nipFile}_${nameFile}_${now.getTime()}.pdf`;
    
    doc.save(filename);
}
window.generateJurnalPDF = generateJurnalPDF;

function generateLaporanKehadiranPDF(kelas, bulan, tahun, reportData, mapel = null) {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF('l', 'mm', 'a4'); // 'l' for landscape

    // Header/Kop Laporan
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(14);
    if (mapel) {
        doc.text(`REKAPITULASI KEHADIRAN SISWA BULANAN - MAPEL ${mapel.toUpperCase()}`, 148, 12, { align: 'center' });
    } else {
        doc.text('REKAPITULASI KEHADIRAN SISWA BULANAN', 148, 12, { align: 'center' });
    }

    // Calculate Academic Year automatically based on the report month & year
    const monthsMap = {
        'Januari': 0, 'Februari': 1, 'Maret': 2, 'April': 3, 'Mei': 4, 'Juni': 5,
        'Juli': 6, 'Agustus': 7, 'September': 8, 'Oktober': 9, 'November': 10, 'Desember': 11
    };
    const reportMonthIdx = monthsMap[bulan] !== undefined ? monthsMap[bulan] : 6;
    const reportYear = parseInt(tahun) || new Date().getFullYear();
    const academicYear = reportMonthIdx >= 6 ? `${reportYear}/${reportYear + 1}` : `${reportYear - 1}/${reportYear}`;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text(`Tahun Pelajaran : ${academicYear}`, 148, 17, { align: 'center' });

    const bkData = JSON.parse(localStorage.getItem('cached_bk') || '[]');
    const bkForClass = bkData.find(b => String(b.KELAS || b.Kelas || b.kelas || '').trim() === kelas.trim());
    
    let waliKelasName = '-';
    if (bkForClass && (bkForClass.WALIKELAS || bkForClass.WaliKelas || bkForClass.walikelas)) {
        waliKelasName = bkForClass.WALIKELAS || bkForClass.WaliKelas || bkForClass.walikelas;
    }
    
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Kelas : ${kelas}`, 14, 25);
    doc.text(`Bulan : ${bulan} ${tahun}`, 14, 30);
    
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    doc.text(`Wali Kelas : ${waliKelasName}`, pageWidth - 14, 25, { align: 'right' });
    let daysInMonth = 31;
    if (reportData.length > 0 && reportData[0].DAILY) {
        daysInMonth = reportData[0].DAILY.length;
    }

    // Prepare table headers
    const headers = ['No', 'Nama Siswa'];
    for (let i = 1; i <= daysInMonth; i++) {
        headers.push(i.toString());
    }
    headers.push('S', 'I', 'A');

    // Prepare table data
    const tableBody = reportData.map(row => {
        const rowData = [row.NO, row.NAMA];
        if (row.DAILY) {
            row.DAILY.forEach(status => rowData.push(status));
        } else {
            // Fallback if daily is somehow missing
            for (let i=0; i<daysInMonth; i++) rowData.push('-');
        }
        rowData.push(row.S, row.I, row.A);
        return rowData;
    });

    const colStyles = {
        0: { halign: 'center', cellWidth: 8 },  // No
        1: { halign: 'left', cellWidth: 45 }    // Nama
    };

    // Days columns width
    for (let i = 2; i < 2 + daysInMonth; i++) {
        colStyles[i] = { halign: 'center', cellWidth: 6 };
    }
    
    // Total S, I, A columns width
    const totalStartIdx = 2 + daysInMonth;
    colStyles[totalStartIdx] = { halign: 'center', cellWidth: 8, fontStyle: 'bold' };
    colStyles[totalStartIdx + 1] = { halign: 'center', cellWidth: 8, fontStyle: 'bold' };
    colStyles[totalStartIdx + 2] = { halign: 'center', cellWidth: 8, fontStyle: 'bold' };

    doc.autoTable({
        startY: 35,
        head: [headers],
        body: tableBody,
        theme: 'grid',
        headStyles: {
            fillColor: [30, 64, 175], // primary color
            textColor: 255,
            fontStyle: 'bold',
            halign: 'center',
            fontSize: 7
        },
        columnStyles: colStyles,
        styles: {
            fontSize: 7,
            cellPadding: 1,
            overflow: 'linebreak'
        },
        alternateRowStyles: {
            fillColor: [248, 250, 252]
        },
        didParseCell: function(data) {
            // Apply colors to specific statuses in the body
            if (data.section === 'body' && data.column.index >= 2 && data.column.index < totalStartIdx) {
                const val = data.cell.raw;
                if (val === 'H') {
                    data.cell.styles.textColor = [16, 185, 129]; // Green
                } else if (val === 'S') {
                    data.cell.styles.textColor = [245, 158, 11]; // Yellow/Orange
                } else if (val === 'I') {
                    data.cell.styles.textColor = [59, 130, 246]; // Blue
                } else if (val === 'A') {
                    data.cell.styles.textColor = [239, 68, 68];  // Red
                } else if (val === 'OFF') {
                    data.cell.styles.textColor = [239, 68, 68]; // Red for OFF
                    data.cell.styles.fontStyle = 'bold';
                    data.cell.styles.fontSize = 5; // Smaller font to fit in narrow cell
                } else if (val === '-') {
                    data.cell.styles.textColor = [200, 200, 200]; // Light gray
                }
            }
        }
    });

    const finalY = doc.lastAutoTable.finalY;
    let signatureY = finalY + 10;
    const margin = 14;

    // Check if there's enough space for signatures
    if (signatureY + 45 > pageHeight - margin) {
        doc.addPage();
        signatureY = margin + 10;
    }

    // Get Signature Data
    const dokData = JSON.parse(localStorage.getItem('cached_dok') || '[]');
    const getDokData = (keyword) => {
        const found = dokData.find(d => {
            const kat = String(d.KATEGORI || d.Kategori || d.kategori || '').toUpperCase();
            return kat.includes(keyword.toUpperCase());
        });
        return found || { Nama: '.......................', NIP: '-' };
    };

    const kepsek = getDokData('KEPALA SEKOLAH');
    const wakakur = getDokData('WAKIL KEPALA SEKOLAH') || getDokData('KURIKULUM');

    const savedUser = JSON.parse(localStorage.getItem('userData') || '{}');
    const guruNip = savedUser.NIP || savedUser.nip || '-';
    
    let teacherName = '.......................';
    if (bkForClass && (bkForClass.GURUBK || bkForClass.GuruBK || bkForClass.gurubk)) {
        teacherName = bkForClass.GURUBK || bkForClass.GuruBK || bkForClass.gurubk;
    } else {
        teacherName = savedUser.NAMA || savedUser.NAMA_GURU || savedUser.nama || '.......................';
    }

    const months = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
    const now = new Date();
    const currentDate = `${now.getDate()} ${months[now.getMonth()]} ${now.getFullYear()}`;

    // Signatures setup (Horizontal layout)
    const signatureWidth = 70;
    const signatureHeight = 20;

    const sig1X = margin;
    const sig2X = (pageWidth / 2) - (signatureWidth / 2);
    const sig3X = pageWidth - margin - signatureWidth;

    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(0, 0, 0);

    // 1. Kepala Sekolah (Kiri)
    doc.text('Mengetahui,', sig1X + signatureWidth / 2, signatureY, { align: 'center' });
    doc.text('Kepala SMK Negeri 1 Bumijawa', sig1X + signatureWidth / 2, signatureY + 4, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    doc.text(kepsek.NAMA || kepsek.Nama || kepsek.nama || '.......................', sig1X + signatureWidth / 2, signatureY + signatureHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${kepsek.NIP || kepsek.Nip || kepsek.nip || '-'}`, sig1X + signatureWidth / 2, signatureY + signatureHeight + 8, { align: 'center' });

    // 2. Wakil Kepala Sekolah (Tengah)
    doc.text('Wakil Kepala Sekolah', sig2X + signatureWidth / 2, signatureY, { align: 'center' });
    doc.text('Bidang Kurikulum', sig2X + signatureWidth / 2, signatureY + 4, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    doc.text(wakakur.NAMA || wakakur.Nama || wakakur.nama || '.......................', sig2X + signatureWidth / 2, signatureY + signatureHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${wakakur.NIP || wakakur.Nip || wakakur.nip || '-'}`, sig2X + signatureWidth / 2, signatureY + signatureHeight + 8, { align: 'center' });

    // 3. Guru Mata Pelajaran (Kanan)
    doc.text('Bumijawa, ' + currentDate, sig3X + signatureWidth / 2, signatureY, { align: 'center' });
    const sigRoleText = mapel ? 'Guru Mata Pelajaran' : 'Guru Bimbingan Konseling';
    doc.text(sigRoleText, sig3X + signatureWidth / 2, signatureY + 4, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    const displayTeacherName = mapel ? (savedUser.NAMA || savedUser.NAMA_GURU || savedUser.nama || '.......................') : teacherName;
    doc.text(displayTeacherName, sig3X + signatureWidth / 2, signatureY + signatureHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${guruNip}`, sig3X + signatureWidth / 2, signatureY + signatureHeight + 8, { align: 'center' });

    const filename = `Kehadiran_${kelas.replace(/\s+/g, '')}_${bulan}_${tahun}.pdf`;
    doc.save(filename);
}

function generateLaporanSemesterPDF(kelas, semesterType, tahun, reportData, mapel = null) {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF('p', 'mm', 'a4'); // 'p' for portrait format
    
    const pageHeight = doc.internal.pageSize.getHeight();
    const pageWidth = doc.internal.pageSize.getWidth();
    const margin = 14;

    // Academic Year display
    const parsedYear = parseInt(tahun) || new Date().getFullYear();
    let academicYear = '';
    let semesterName = '';
    
    if (semesterType === 'ganjil') {
        academicYear = `${parsedYear}/${parsedYear + 1}`;
        semesterName = 'GANJIL';
    } else {
        academicYear = `${parsedYear - 1}/${parsedYear}`;
        semesterName = 'GENAP';
    }

    // Kop Laporan
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(14);
    if (mapel) {
        doc.text(`REKAPITULASI KEHADIRAN SISWA PER SEMESTER - MAPEL ${mapel.toUpperCase()}`, pageWidth / 2, 15, { align: 'center' });
    } else {
        doc.text('REKAPITULASI KEHADIRAN SISWA PER SEMESTER', pageWidth / 2, 15, { align: 'center' });
    }

    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text(`Tahun Pelajaran : ${academicYear}`, pageWidth / 2, 20, { align: 'center' });
    doc.text(`Semester : ${semesterName}`, pageWidth / 2, 25, { align: 'center' });

    // Retrieve BK data for homeroom teacher name
    const bkData = JSON.parse(localStorage.getItem('cached_bk') || '[]');
    const bkForClass = bkData.find(b => String(b.KELAS || b.Kelas || b.kelas || '').trim() === kelas.trim());
    
    let waliKelasName = '-';
    if (bkForClass && (bkForClass.WALIKELAS || bkForClass.WaliKelas || bkForClass.walikelas)) {
        waliKelasName = bkForClass.WALIKELAS || bkForClass.WaliKelas || bkForClass.walikelas;
    }

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Kelas : ${kelas}`, margin, 35);
    doc.text(`Wali Kelas : ${waliKelasName}`, pageWidth - margin, 35, { align: 'right' });

    // Prepare table headers and rows
    const headers = [['No', 'Nama Siswa', 'Sakit (S)', 'Izin (I)', 'Alfa (A)', 'Total Absen']];
    const rows = reportData.map((row, idx) => {
        const total = row.S + row.I + row.A;
        return [
            idx + 1,
            row.NAMA,
            row.S,
            row.I,
            row.A,
            total
        ];
    });

    // Generate table
    doc.autoTable({
        startY: 40,
        head: headers,
        body: rows,
        margin: { left: margin, right: margin },
        theme: 'grid',
        styles: {
            fontSize: 9,
            cellPadding: 3,
            valign: 'middle',
            halign: 'center',
            lineWidth: 0.15,
            lineColor: [100, 116, 139] // Slate-400 color for sharp, visible borders
        },
        columnStyles: {
            0: { width: 10 },
            1: { halign: 'left', width: 80 },
            2: { textColor: [245, 158, 11] }, // Sakit (Yellow/Orange)
            3: { textColor: [59, 130, 246] }, // Izin (Blue)
            4: { textColor: [239, 68, 68] },  // Alfa (Red)
            5: { fontStyle: 'bold' }          // Total Absen
        },
        headStyles: {
            fillColor: [30, 64, 175], // Deep primary blue
            textColor: [255, 255, 255],
            fontStyle: 'bold'
        },
        alternateRowStyles: {
            fillColor: [248, 250, 252]
        }
    });

    const finalY = doc.lastAutoTable.finalY;
    let signatureY = finalY + 12;

    // Check if there's enough space for signatures
    if (signatureY + 45 > pageHeight - margin) {
        doc.addPage();
        signatureY = margin + 10;
    }

    // Get Signature Data
    const dokData = JSON.parse(localStorage.getItem('cached_dok') || '[]');
    const getDokData = (keyword) => {
        const found = dokData.find(d => {
            const kat = String(d.KATEGORI || d.Kategori || d.kategori || '').toUpperCase();
            return kat.includes(keyword.toUpperCase());
        });
        return found || { Nama: '.......................', NIP: '-' };
    };

    const kepsek = getDokData('KEPALA SEKOLAH');
    const wakakur = getDokData('WAKIL KEPALA SEKOLAH') || getDokData('KURIKULUM');

    const savedUser = JSON.parse(localStorage.getItem('userData') || '{}');
    const guruNip = savedUser.NIP || savedUser.nip || '-';
    
    let teacherName = '.......................';
    if (bkForClass && (bkForClass.GURUBK || bkForClass.GuruBK || bkForClass.gurubk)) {
        teacherName = bkForClass.GURUBK || bkForClass.GuruBK || bkForClass.gurubk;
    } else {
        teacherName = savedUser.NAMA || savedUser.NAMA_GURU || savedUser.nama || '.......................';
    }

    const months = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
    const now = new Date();
    const currentDate = `${now.getDate()} ${months[now.getMonth()]} ${now.getFullYear()}`;

    // Signatures setup for Portrait (Single row horizontal block)
    const sigColWidth = 55;
    const sigHeight = 22;

    const sigLeftX = margin;
    const sigCenterX = (pageWidth / 2) - (sigColWidth / 2);
    const sigRightX = pageWidth - margin - sigColWidth;

    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(0, 0, 0);

    // 1. Kepala Sekolah (Kiri)
    doc.text('Mengetahui,', sigLeftX + sigColWidth / 2, signatureY, { align: 'center' });
    doc.text('Kepala SMK Negeri 1 Bumijawa', sigLeftX + sigColWidth / 2, signatureY + 4, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    doc.text(kepsek.NAMA || kepsek.Nama || kepsek.nama || '.......................', sigLeftX + sigColWidth / 2, signatureY + sigHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${kepsek.NIP || kepsek.Nip || kepsek.nip || '-'}`, sigLeftX + sigColWidth / 2, signatureY + sigHeight + 8, { align: 'center' });

    // 2. Waka Kurikulum (Tengah)
    doc.text('Wakil Kepala Sekolah', sigCenterX + sigColWidth / 2, signatureY, { align: 'center' });
    doc.text('Bidang Kurikulum', sigCenterX + sigColWidth / 2, signatureY + 4, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    doc.text(wakakur.NAMA || wakakur.Nama || wakakur.nama || '.......................', sigCenterX + sigColWidth / 2, signatureY + sigHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${wakakur.NIP || wakakur.Nip || wakakur.nip || '-'}`, sigCenterX + sigColWidth / 2, signatureY + sigHeight + 8, { align: 'center' });

    // 3. Guru BK / Mapel (Kanan)
    doc.text('Bumijawa, ' + currentDate, sigRightX + sigColWidth / 2, signatureY, { align: 'center' });
    const sigRoleText = mapel ? 'Guru Mata Pelajaran' : 'Guru Bimbingan Konseling';
    doc.text(sigRoleText, sigRightX + sigColWidth / 2, signatureY + 4, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    const displayTeacherName = mapel ? (savedUser.NAMA || savedUser.NAMA_GURU || savedUser.nama || '.......................') : teacherName;
    doc.text(displayTeacherName, sigRightX + sigColWidth / 2, signatureY + sigHeight + 4, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.text(`NIP. ${guruNip}`, sigRightX + sigColWidth / 2, signatureY + sigHeight + 8, { align: 'center' });

    const filename = `Rekap_Semester_${semesterType.toUpperCase()}_${kelas.replace(/\s+/g, '')}_${tahun}.pdf`;
    doc.save(filename);
}

window.generateLaporanKehadiranPDF = generateLaporanKehadiranPDF;
window.generateLaporanSemesterPDF = generateLaporanSemesterPDF;
